import React from 'react';
import { cuentasContables } from './data/cuentas';
import './styles/global.css';

function App() {
  const { empresa, periodo, activo, pasivo, capital, resultados } = cuentasContables;

  const totalCirculante = activo.circulante.reduce((a, b) => a + b.saldo, 0);
  const totalNoCirculante = activo.noCirculante.reduce((a, b) => a + b.saldo, 0);
  const totalActivo = totalCirculante + totalNoCirculante;

  const totalPasivo = pasivo.cortoPlazo.reduce((a, b) => a + b.saldo, 0);
  const totalCapital = capital.social + capital.utilidadNeta;

  const solvencia = (totalCirculante / totalPasivo).toFixed(2);
  const roe = ((capital.utilidadNeta / totalCapital) * 100).toFixed(2);

  return (
    <div className="container">
      <header>
        <h1>{empresa}</h1>
        <p>Dashboard de Inteligencia Financiera • {periodo}</p>
      </header>

      <div className="grid">
        {/* ESTADO DE RESULTADOS */}
        <section className="card">
          <h2>Estado de Resultados</h2>
          <div className="row"><span>Ventas Netas</span><span>$ {resultados.ventas.toLocaleString()}</span></div>
          <div className="row"><span>(-) Costo de Ventas</span><span>$ {resultados.costoVentas.toLocaleString()}</span></div>
          <div className="row highlighted"><strong>Utilidad Bruta</strong><strong>$ {(resultados.ventas - resultados.costoVentas).toLocaleString()}</strong></div>
          <div className="row"><span>(-) Gastos de Administración</span><span>$ {resultados.gastosAdmon.toLocaleString()}</span></div>
          <div className="row"><span>(+) Otros Ingresos</span><span>$ {resultados.otrosIngresos.toLocaleString()}</span></div>
          <div className="row"><span>(-) Impuestos (ISR/PTU)</span><span>$ {resultados.impuestos.toLocaleString()}</span></div>
          <div className="row utility"><strong>UTILIDAD NETA</strong><strong>$ {capital.utilidadNeta.toLocaleString()}</strong></div>
        </section>

        {/* ANÁLISIS RÁPIDO */}
        <section className="card">
          <h2>Métricas Clave</h2>
          <div className="analysis-item" style={{marginBottom: '24px'}}>
            <span className="analysis-badge">Solvencia</span>
            <div className="row" style={{border: 'none'}}><strong>Ratio Actual:</strong> <strong style={{fontSize: '1.5rem', color: 'var(--blue-primary)'}}>{solvencia}</strong></div>
            <p className="desc">Capacidad para cubrir pasivos inmediatos. Un ratio de {solvencia} indica una posición financiera sólida.</p>
          </div>
          <div className="analysis-item">
            <span className="analysis-badge">Rentabilidad</span>
            <div className="row" style={{border: 'none'}}><strong>ROE:</strong> <strong style={{fontSize: '1.5rem', color: 'var(--blue-primary)'}}>{roe}%</strong></div>
            <p className="desc">Rendimiento sobre el capital invertido. Refleja la eficiencia en la generación de utilidades.</p>
          </div>
        </section>
      </div>

      {/* BALANCE GENERAL */}
      <section className="card">
        <h2>Balance General</h2>
        <div className="grid">
          <div className="column">
            <h3>ACTIVO</h3>
            <p className="sub">Circulante</p>
            {activo.circulante.map(c => <div className="row" key={c.nombre}><span>{c.nombre}</span><span>$ {c.saldo.toLocaleString()}</span></div>)}
            <p className="sub">No Circulante</p>
            {activo.noCirculante.map(c => <div className="row" key={c.nombre}><span>{c.nombre}</span><span>$ {c.saldo.toLocaleString()}</span></div>)}
            <div className="row total"><strong>TOTAL ACTIVO</strong><strong>$ {totalActivo.toLocaleString()}</strong></div>
          </div>
          <div className="column">
            <h3>PASIVO + CAPITAL</h3>
            <p className="sub">Corto Plazo</p>
            {pasivo.cortoPlazo.map(p => <div className="row" key={p.nombre}><span>{p.nombre}</span><span>$ {p.saldo.toLocaleString()}</span></div>)}
            <p className="sub">Capital Contable</p>
            <div className="row"><span>Capital Social</span><span>$ {capital.social.toLocaleString()}</span></div>
            <div className="row"><span>Utilidad del Ejercicio</span><span>$ {capital.utilidadNeta.toLocaleString()}</span></div>
            <div className="row total"><strong>TOTAL PASIVO + CAPITAL</strong><strong>$ {(totalPasivo + totalCapital).toLocaleString()}</strong></div>
          </div>
        </div>
      </section>
    </div>
  );
}

export default App;
